class Editor:
    def __init__(
        self,
        editor: str | None = None,
        env: cabc.Mapping[str, str] | None = None,
        require_save: bool = True,
        extension: str = ".txt",
        process_priority: str | None = None,
    ) -> None:
        self.editor = editor
        self.env = env
        self.require_save = require_save
        self.extension = extension
        self.process_priority = process_priority

    def get_editor(self) -> str:
        if self.editor is not None:
            return self.editor
        for key in "VISUAL", "EDITOR":
            rv = os.environ.get(key)
            if rv:
                return rv
        if WIN:
            return "notepad"
        for editor in "sensible-editor", "vim", "nano":
            if os.system(f"which {editor} >/dev/null 2>&1") == 0:
                return editor
        return "vi"

    def _priority_popen_kwargs(self) -> dict[str, t.Any]:
        if self.process_priority is None:
            return {}

        if WIN:
            priority_class = _WIN_PRIORITY_CLASSES.get(self.process_priority)

            if priority_class is None:
                return {}

            return {"creationflags": priority_class}

        nice_value = _NICE_VALUES.get(self.process_priority)

        if not nice_value:
            return {}

        def set_priority() -> None:
            try:
                os.nice(nice_value)
            except OSError:
                pass

        return {"preexec_fn": set_priority}

    def edit_files(self, filenames: cabc.Iterable[str]) -> None:
        import subprocess

        editor = self.get_editor()
        environ: dict[str, str] | None = None

        if self.env:
            environ = os.environ.copy()
            environ.update(self.env)

        exec_parts = [editor, *(f'"{filename}"' for filename in filenames)]
        command = " ".join(exec_parts)

        try:
            c = subprocess.Popen(
                command, env=environ, shell=True, **self._priority_popen_kwargs()
            )
            exit_code = c.wait()
            if exit_code != 0:
                raise ClickException(
                    _("{editor}: Editing failed").format(editor=editor)
                )
        except OSError as e:
            raise ClickException(
                _("{editor}: Editing failed: {e}").format(editor=editor, e=e)
            ) from e

